301→/**
302→ * Get the current indentation of the line containing the [ASTNode]. By default, this indentation starts with a newline (\n) character.
303→ */
304→public fun ASTNode.indent(includeNewline: Boolean = true): String =
305→    leaves(forward = false)
306→        .firstOrNull { it.isWhiteSpaceWithNewline() }
307→        ?.text
308→        ?.substringAfterLast('\n')
309→        .orEmpty() // Fallback if node is not preceded by any newline character
310→        .applyIf(includeNewline) { prefixIfNot("\n") }
