312→/**
313→ *  Print content of a node and the element type of the node, its parent and its direct children. Utility is meant to
314→ *  be used during development only. Please do not remove.
315→ */
316→@Suppress("unused")
317→public fun ASTNode.logStructure(): ASTNode =
318→    also {
319→        println("Processing ${text.replaceTabAndNewline()} : Type $elementType with parent ${treeParent?.elementType} ")
320→        children()
321→            .toList()
322→            .map {
323→                println("  ${it.text.replaceTabAndNewline()} : Type ${it.elementType}")
324→            }
325→    }
