327→private fun String.replaceTabAndNewline(): String = replace("\t", "\\t").replace("\n", "\\n")
328→
329→/**
330→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
331→ * the boundary nodes [from] or [to] contains a newline.
332→ */
333→public fun hasNewLineInClosedRange(
334→    from: ASTNode,
335→    to: ASTNode,
336→): Boolean = leavesInClosedRange(from, to).any { it.textContains('\n') }
337→
338→/**
339→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
340→ * should not contain a newline.
341→ */
342→public fun noNewLineInClosedRange(
343→    from: ASTNode,
344→    to: ASTNode,
345→): Boolean = leavesInClosedRange(from, to).none { it.textContains('\n') }
346→
347→/**
348→ * Verifies that no leaf contains a newline in the open range [from] - [to]. This means that the boundary nodes are excluded from the range
349→ * in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first leaf node in the sequence is the first
350→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node prior
351→ * to this [CompositeElement].
352→ */
353→public fun noNewLineInOpenRange(
354→    from: ASTNode,
355→    to: ASTNode,
356→): Boolean = leavesInOpenRange(from, to).none { it.textContains('\n') }
357→
358→/**
359→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
360→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
361→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
362→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
363→ */
364→public fun leavesInOpenRange(
365→    from: ASTNode,
366→    to: ASTNode,
367→): Sequence<ASTNode> =
368→    from
369→        .leaves()
370→        .takeWhile { it != to && it != to.lastChildLeafOrSelf() }
371→
372→/**
373→ * Creates a sequence of leaf nodes in the closed range [from] - [to]. This means that the boundary nodes are included from the range in
374→ * case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first leaf node in the sequence is the first
375→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node of
376→ * this [CompositeElement].
377→ */
378→public fun leavesInClosedRange(
379→    from: ASTNode,
380→    to: ASTNode,
381→): Sequence<ASTNode> {
382→    val stopAtLeaf =
383→        to
384→            .lastChildLeafOrSelf()
385→            .nextLeaf()
386→    return from
387→        .firstChildLeafOrSelf()
388→        .leavesIncludingSelf()
389→        .takeWhile { it != stopAtLeaf }
390→}
391→
392→public fun ASTNode.isValOrVarKeyword(): Boolean = elementType == VAL_KEYWORD || elementType == VAR_KEYWORD || elementType == VARARG_KEYWORD
393→
394→/**
395→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
396→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
397→ */
398→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
399→    val sequence =
400→        if (isLeaf()) {
401→            sequenceOf(this)
402→        } else {
403→            emptySequence()
404→        }
405→    return sequence.plus(leaves(forward))
406→}
407→
408→/**
409→ * Get all leaves on the same line as the given node including the whitespace indentation. Note that the whitespace indentation may start
410→ * with zero or more newline characters.
411→ */
412→public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
413→    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
414→    return getFirstLeafOnLineOrSelf()
415→        .leavesIncludingSelf()
416→        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
417→}
418→
419→internal fun ASTNode.getFirstLeafOnLineOrSelf() = prevLeaf { it.textContains('\n') || it.prevLeaf() == null }!!
420→
421→internal fun ASTNode.getLastLeafOnLineOrNull() = nextLeaf { it.textContains('\n') }?.prevLeaf()
422→
423→/**
424→ * Get the total length of all leaves on the same line as the given node including the whitespace indentation but excluding all leading
425→ * newline characters in the whitespace indentation.
426→ */
427→public fun ASTNode.lineLengthWithoutNewlinePrefix(): Int =
428→    leavesOnLine()
429→        .joinToString(separator = "") { it.text }
430→        // If a line is preceded by a blank line then the ident contains multiple newline chars
431→        .dropWhile { it == '\n' }
432→        // In case the last element on the line would contain a newline then only include chars before that newline. Note that this should
433→        // not occur if the AST is parsed correctly
434→        .takeWhile { it != '\n' }
435→        .length
