}", "new_string": "/**
 * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
 * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
 * added after the last child leaf.
 */
public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
    if (this is LeafElement) {
        if (this.elementType == WHITE_SPACE) {
            return replaceWhitespaceWith(text)
        }
        val next = treeNext
        if (next != null) {
            if (next.elementType == WHITE_SPACE) {
                next.replaceWhitespaceWith(text)
            } else {
                PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
                    (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
                }
            }
        } else {
            // The node is the last leaf element inside its parent. Find the correct position to insert the whitespace
            // by going up the tree until an ancestor with a treeNext is found.
            var ancestor: ASTNode? = treeParent
            while (ancestor != null && ancestor.treeNext == null) {
                ancestor = ancestor.treeParent
            }
            if (ancestor != null) {
                val ancestorNext = ancestor.treeNext!!
                if (ancestorNext.elementType == WHITE_SPACE) {
                    ancestorNext.replaceWhitespaceWith(text)
                } else {
                    // Insert whitespace before ancestorNext at the ancestor's parent level
                    ancestor.treeParent?.addChild(PsiWhiteSpaceImpl(text), ancestorNext)
                }
            }
        }
    } else {
        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
    }
}"}

